import React from 'react'
import { Checkbox,Collapse,Panel } from 'antd';

const delivery = [
    {
        "_id": 1,
        "name": "New Products"
    },
    {
        "_id": 2,
        "name": "Free Shipping"
    },
    {
        "_id": 3,
        "name": "One Day Delivery"
    },
    {
        "_id": 4,
        "name": "Two Day Delivery"
    }]


    const renderCheckboxLists =()=>delivery.map((value,index)=>(
        <React.Fragment key={index}>
            <Checkbox
            onChange
            type="checkbox"
            checked
            />
            <span>{value.name}</span>
        </React.Fragment>
    ))
function CheckBox() {
    return (
        <div>
            <Collapse defaultActiveKey={['0']}>
                <Panel header key="1">
                    {renderCheckboxLists()}
                </Panel>
            </Collapse>
        </div>
    )
}

export default CheckBox
